function [nmbScn,scan,scnDir,imgSz] = fScanDirLstV02(mDir,inScn,diagDN,diagN)%% search directory, return scan list with log and images within%% [nmbScn,scan,scnDir] = fScanDirLstV02(mDir,inScn,diagD,diagN)%% mDir: mother directory, usually '../scans'% inScan: input scan to go through (not necessary to exist)% diagD: diagnostic directory name, like 'OTR'% diagN: diagnostic file name, like 'OTR_'%% nmbScn: number of scan to go through% scan: array of scan numbers% scnDir: scan directory to go through% imgSz: image size, height-width to allocate%% Written by Kei Nakamura% Created on Monday, June 1st 2009.% Modified on Friday, June 11th 2010.%% main bodyjj = 1;     % index for output scanscnDir{1} = 'null';           % in case scan doesn't exist, to retun nullscan(1) = -1;                   % nullfor ii=1:numel(inScn);  % input scan loop    scanNS = fGet3NmbStringV01(inScn(ii));  % 3 digit scan number string    scnD = [mDir,'/Scan',scanNS];       % scan directory    diagD = [scnD,'/',diagDN];   % diag directory    logEx = exist([scnD,'/ScanDataScan',scanNS,'.txt']);    % log exist        imgList = dir([diagD,'/*',diagN,'*.png']);    % list of image    imgEx = abs(sign(numel(imgList)));      % image exist    bgList = dir([diagD,'/*',diagN,'BG*.png']); % list of bg    bgEx = abs(sign(numel(bgList)));      % background exist    imgInf = imfinfo([diagD,'/',bgList(1).name]);    imgSz(1) = imgInf.Height;   % image row number    imgSz(2) = imgInf.Width;    % image clm number        if logEx&&imgEx&&bgEx        scan(jj) = inScn(ii);           % scan number        scnDir{jj} = ['Scan',scanNS];    % scan directory name        jj = jj + 1;    endendnmbScn = jj -1; % number of scans for output
